import requests
import pytest

BASE = "https://api.example.com/v1"
TOKEN = "test-bearer-token"
HEADERS = {"Authorization": f"Bearer {TOKEN}", "Content-Type": "application/json"}

def test_create_order_happy_path():
    payload = {"customerId": "c-123", "items": [{"sku": "SKU-1", "quantity": 2}]}
    r = requests.post(f"{BASE}/orders", json=payload, headers=HEADERS)
    assert r.status_code == 201
    body = r.json()
    assert "id" in body
    assert body["status"] == "created"

def test_missing_customer_id_returns_400():
    payload = {"items": [{"sku": "SKU-1", "quantity": 2}]}
    r = requests.post(f"{BASE}/orders", json=payload, headers=HEADERS)
    assert r.status_code == 400

@pytest.mark.parametrize("qty", [0, -1])
def test_invalid_quantity_returns_422(qty):
    payload = {"customerId": "c-123", "items": [{"sku": "SKU-1", "quantity": qty}]}
    r = requests.post(f"{BASE}/orders", json=payload, headers=HEADERS)
    assert r.status_code == 422

def test_no_auth_returns_401():
    payload = {"customerId": "c-123", "items": [{"sku": "SKU-1", "quantity": 1}]}
    r = requests.post(f"{BASE}/orders", json=payload)  # no auth header
    assert r.status_code == 401
